sql:
SELECT estimated_duration 
FROM upgrade_tasks 
WHERE criticality_level = 'high';

SELECT COUNT(audit_id) AS total_non_compliant_upgrades
FROM upgrade_audits
WHERE compliance_status = 'non-compliant';

SELECT AVG(estimated_duration) AS average_task_duration
FROM upgrade_tasks
WHERE criticality_level = 'high';

external_knowledge:
- A task is considered "successfully completed" if its status in the task logs is 'success';
- "Admin user" refers to the user with a user ID of 0;
- "Tasks that failed because they involved inactive objects" refers to tasks with technical errors and SAP notes containing the phrase 'inactive%object%';

sql:
SELECT task_id 
FROM upgrade_tasks 
WHERE task_id NOT IN (
  SELECT dependent_task_id 
  FROM tasks_dependencies
);

SELECT task_description
FROM upgrade_tasks
WHERE estimated_duration = (
  SELECT MAX(estimated_duration)
  FROM upgrade_tasks
);

SELECT task_description
FROM upgrade_tasks
WHERE task_id = 0;

SELECT task_id, MIN(execution_time) AS min_execution_time, MAX(execution_time) AS max_execution_time 
FROM executed_steps 
GROUP BY task_id;

SELECT COUNT(*) 
FROM task_logs
WHERE status = 'success' AND execution_date >= DATE('now', '-30 days');
